try {
const fileId = $input.first().json.id;

const prompt = "Analise o documento financeiro e responda APENAS com JSON valido, sem markdown.

PASSO 1 - Identifique o tipo:
- "comprovante_simples": PIX, TED, DOC, transferencia, pagamento de boleto unico
- "cupom_fiscal": cupom/nota fiscal de mercado, supermercado, loja, com lista de produtos

PASSO 2 - Extraia conforme o tipo detectado:

Para comprovante_simples, retorne:
{
  "tipo_documento": "comprovante_simples",
  "data_transacao": "dd/MM/yyyy",
  "transacao": "descricao curta (ex: PIX para Joao, Pagamento fatura Nubank)",
  "categoria": "entrada ou saida",
  "valor": 0.00,
  "estabelecimento": null,
  "itens": []
}

Para cupom_fiscal, retorne:
{
  "tipo_documento": "cupom_fiscal",
  "data_transacao": "dd/MM/yyyy",
  "transacao": "Compra em [NOME_DO_ESTABELECIMENTO]",
  "categoria": "saida",
  "valor": 0.00,
  "estabelecimento": "nome da loja/mercado",
  "itens": [
    {
      "descricao": "nome do produto",
      "quantidade": 1,
      "valor_unitario": 0.00,
      "valor_total": 0.00
    }
  ]
}

Regras criticas:
- categoria: "entrada" se o titular RECEBEU o valor; "saida" se PAGOU ou COMPROU
- Cupons fiscais sao SEMPRE "saida"
- valor = total pago (numero puro, sem R$, sem + ou -)
- O ano atual e " + new Date().getFullYear() + ". Se o documento nao mostrar o ano com clareza absoluta, retorne null no campo data_transacao — NUNCA tente adivinhar o ano
- Se nao encontrar data ou o ano estiver ilegivel, use null
- Valores numericos sem simbolos";

const requestBody = {
  model: "gpt-5",
  input: [
    { role: "system", content: "Voce e um extrator de dados de documentos financeiros. Analise o documento e extraia as informacoes. Responda APENAS com JSON valido, sem markdown, sem explicacoes." },
    {
      role: "user",
      content: [
        { type: "input_file", file_id: fileId },
        { type: "input_text", text: prompt }
      ]
    }
  ]
};

return [{ json: { requestBody: JSON.stringify(requestBody) } }];
} catch (e) {
  return [{ json: { success: false, error_code: 'CODE_ERROR', message: '[FN - Prepara OCR PDF] ' + (e.message || 'Erro desconhecido') } }];
}

const raw = $input.first().json;
let content = '';
try {
  content = raw.choices[0].message.content;
} catch (e1) {
  try {
    const msgBlock = raw.output.find(o => o.type === 'message');
    const textBlock = msgBlock.content.find(c => c.type === 'output_text');
    content = textBlock.text;
  } catch (e2) {
    throw new Error('Resposta Vision invalida: ' + JSON.stringify(raw).substring(0, 500));
  }
}

content = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let parsed;
try {
  parsed = JSON.parse(content);
} catch (e) {
  throw new Error('JSON invalido: ' + content);
}

let dataCorrigida = false;
let dataOriginalOCR = null;

if (parsed.data_transacao) {
  const partes = parsed.data_transacao.split('/');
  if (partes.length === 3) {
    const anoOCR = parseInt(partes[2]);
    const anoAtual = new Date().getFullYear();
    if (isNaN(anoOCR) || anoOCR < anoAtual - 1 || anoOCR > anoAtual + 1) {
      dataOriginalOCR = parsed.data_transacao;
      partes[2] = String(anoAtual);
      parsed.data_transacao = partes.join('/');
      dataCorrigida = true;
    }
  }
}

const categoriaRaw = (parsed.categoria || '').toLowerCase().trim();
const isEntrada = categoriaRaw.includes('entrada');
const valor = parseFloat(parsed.valor) || 0;
const tipoDoc = parsed.tipo_documento || 'comprovante_simples';
const itens = parsed.itens || [];

const categoriasInvalidas = [
  'entrada','saida','saída','gasto','despesa',
  'receita','debito','débito','credito','crédito'
];

const categoriaSanitizada = (() => {
  if (categoriasInvalidas.includes(categoriaRaw)) {
    const ref = ((parsed.estabelecimento || '') + ' ' + (parsed.transacao || '')).toLowerCase();
    if (/receb|cliente|honorar|freela|comiss/.test(ref)) return 'Receita';
    if (/farm|drog|medic|saude|saúde|hospital|clinic|plano/.test(ref)) return 'Saúde';
    if (/mercado|superm|hortifrut|açougue|padaria|cafe|café/.test(ref)) return 'Alimentação';
    if (/restaur|lanche|pizza|burger|ifood|delivery|sushi/.test(ref)) return 'Alimentação';
    if (/uber|99|taxi|táxi|posto|gasolina|combustiv|shell|ipiranga/.test(ref)) return 'Transporte';
    if (/escola|facul|curso|mensalidade|colegio|colégio/.test(ref)) return 'Educação';
    if (/aluguel|condomin|energia|agua|água|internet|luz|gas|gás/.test(ref)) return 'Moradia';
    if (/amazon|shopee|magazine|americanas|casas bahia|lojas/.test(ref)) return 'Compras';
    if (/netflix|spotify|amazon prime|disney|hbo|streaming/.test(ref)) return 'Assinaturas';
    if (/salario|salário|pagamento recebido|transferencia recebida/.test(ref)) return 'Salário';
    return 'Outros';
  }
  return categoriaRaw.charAt(0).toUpperCase() + categoriaRaw.slice(1);
})();

if (valor === 0) {
  throw new Error('Valor do comprovante é zero ou não foi identificado pelo OCR. Solicite ao usuário que reenvie o documento com melhor qualidade de imagem.');
}

const dataFinal = (() => {
  if (parsed.data_transacao) return parsed.data_transacao;
  const hoje = new Date();
  const dd = String(hoje.getDate()).padStart(2, '0');
  const mm = String(hoje.getMonth() + 1).padStart(2, '0');
  const yyyy = hoje.getFullYear();
  return dd + '/' + mm + '/' + yyyy;
})();

let itensFormatados = '';
if (itens.length > 0) {
  itensFormatados = itens
    .map(i => '  \u2022 ' + i.descricao + ' (' + i.quantidade + 'x) \u2014 R$ ' + parseFloat(i.valor_total).toFixed(2))
    .join('\n');
}

return [{
  json: {
    tipo_documento:   tipoDoc,
    data_transacao:   dataFinal,
    transacao:        parsed.transacao || 'Comprovante financeiro',
    estabelecimento:  parsed.estabelecimento || null,
    categoria:        categoriaSanitizada,
    entrada:          isEntrada ? valor : 0,
    saida:            isEntrada ? 0 : valor,
    itens:            itens,
    itens_formatados: itensFormatados,
    tem_itens:        itens.length > 0,
    dataCorrigida:    dataCorrigida,
    dataOriginalOCR:  dataOriginalOCR
  }
}];

