const nl = String.fromCharCode(10);

let ctx = {};
try { ctx = $('FN - Contexto Resultado Arquivo').item?.json ?? {}; } catch(e) {}
try { if (!ctx || Object.keys(ctx).length === 0) ctx = $('FN - Contexto Texto').item?.json ?? {}; } catch(e) {}

const tipoResultado = ctx.tipo_resultado ?? '';
const chatContext = ctx.chat_context ?? ctx['Chat Context '] ?? ctx['Chat Context'] ?? '';
const fileURL = ctx.fileURL ?? '';
const textoPdf = ctx.texto_pdf ?? '';

let usuarioId = ctx.usuario_id ?? '';
if (!usuarioId) {
  try { usuarioId = $('FN - Seta Dados Entrada').item?.json?.usuario_id ?? ''; } catch(e) {}
}

const faturaId = ctx.fatura_id ?? '';

let instrucao = chatContext;

if (tipoResultado === 'fatura_cartao_processada') {
  instrucao += nl + nl +
    'INSTRUCAO OBRIGATORIA: O arquivo enviado e uma fatura de cartao.' + nl +
    'Chame IMEDIATAMENTE ExtratarFatura com:' + nl +
    '- fileURL: ' + fileURL + nl +
    '- usuario_id: ' + usuarioId + nl +
    'Nao responda sem chamar a tool primeiro.';
}

if (tipoResultado === 'conta_processada') {
  if (!textoPdf || textoPdf.trim() === '') {
    instrucao += nl + nl +
      'INSTRUCAO OBRIGATORIA: O arquivo enviado e uma conta/boleto, mas nao foi possivel extrair o texto automaticamente (PDF escaneado ou imagem sem OCR).' + nl +
      'Informe ao usuario de forma amigavel que nao conseguiu ler os dados automaticamente e peca que ele informe:' + nl +
      '- Nome da empresa (ex: Vivo, Enel, Sabesp)' + nl +
      '- Valor a pagar' + nl +
      '- Data de vencimento' + nl +
      'Apos receber os dados do usuario, chame IncluirConta normalmente.' + nl +
      'usuario_id: ' + usuarioId;
  } else {
    instrucao += nl + nl +
      'INSTRUCAO OBRIGATORIA: O arquivo enviado e uma conta/boleto.' + nl +
      'Chame IMEDIATAMENTE IncluirConta extraindo os dados do texto abaixo.' + nl +
      'Texto extraido do arquivo:' + nl +
      textoPdf + nl + nl +
      'Parametros obrigatorios:' + nl +
      '- destinatario: nome da empresa emissora (ex: Vivo, Sabesp, Enel)' + nl +
      '- valor_total: valor numerico a pagar' + nl +
      '- data_fatura: data de vencimento no formato dd/MM/yyyy' + nl +
      '- numero_fatura: numero identificador ou N/A' + nl +
      '- categoria: inferir pelo tipo de servico (ex: internet/fibra/tv -> "Internet / TV", energia eletrica -> "Energia Eletrica", agua -> "Agua / Saneamento", telefone/celular -> "Telefone / Celular", gas -> "Gas", aluguel -> "Aluguel", condominio -> "Condominio", plano saude -> "Plano de Saude", escola -> "Mensalidade Escola", streaming -> "Streaming")' + nl +
      '- arquivo_url: ' + fileURL + nl +
      '- usuario_id: ' + usuarioId + nl +
      'Nao pergunte ao usuario — registre automaticamente e confirme apos.';
  }
}

if (faturaId) {
  instrucao += nl + nl +
    'Contexto de fatura ativa: fatura_id=' + faturaId +
    ', usuario_id=' + usuarioId;
}

if (!instrucao || instrucao.trim() === '') {
  let fallback = '';
  try { fallback = $('FN - Seta Dados Entrada').item?.json?.mensagem ?? ''; } catch(e) {}
  if (!fallback || fallback.trim() === '') {
    fallback = 'Olá! Como posso ajudar com suas finanças?';
  }
  instrucao = fallback;
}

return [{ json: { prompt: instrucao } }];

